import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"82. Fitness For Work","description":"","frontmatter":{"title":"82. Fitness For Work","eba":"Health Allied & Managers Admin 2021-2025","topics":["ohs"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/ohs/82-fitness-for-work.md","filePath":"ebas/has-managers-admin/common-terms/ohs/82-fitness-for-work.md"}'),s={name:"ebas/has-managers-admin/common-terms/ohs/82-fitness-for-work.md"};function a(i,e,p,l,h,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_82-fitness-for-work" tabindex="-1">82. Fitness For Work <a class="header-anchor" href="#_82-fitness-for-work" aria-label="Permalink to &quot;82. Fitness For Work&quot;">​</a></h1><p><strong>82.1</strong> Fit for Work</p><p>PART J – OCCUPATONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p><strong>(a)</strong> The Employer is responsible for providing a workplace that is safe and without risk to health for Employees, so far as is reasonably practicable.</p><p><strong>(b)</strong> Each Employee is responsible for ensuring that they are fit to perform their duties without risk to the safety, health and well-being of themselves and others within the workplace. This responsibility includes compliance with reasonable measures put in place by the Employer and any related occupational health and safety requirements.</p><p><strong>82.2</strong> Addressing concerns about Fitness for Work</p><p><strong>(a)</strong> In the event the Employee&#39;s manager forms a reasonable belief (as defined at subclause 82.2(b) below that an Employee may be unfit to perform their duties, the Employer will act in a timely manner to promote physical, mental and emotional health so that employees can safely undertake and sustain work.</p><p><strong>(b)</strong> In this clause reasonable belief means a belief based on sufficient evidence that supports a conclusion on the balance of probabilities. Nothing in this clause 82.2(b) permits an Employer to act contrary to the Health Records Act 2001 (Vic).</p><p><strong>(c)</strong> In this clause treating medical practitioner may, where relevant, also include programs such as the ‘Mind Your Head’ program, or a psychologist.</p><p><strong>(d)</strong> The Employer will:</p><p><strong>(i)</strong> take all reasonable steps to give the Employee an opportunity to answer any concerns which are the subject of the reasonable belief;</p><p><strong>(ii)</strong> recognise the Employee&#39;s right to have a representative, including a Union representative, at any time when meeting with the Employer;</p><p><strong>(iii)</strong> genuinely consider the Employee&#39;s response with a view to promoting physical, mental and emotional health so that Employees can safely undertake and sustain work; and</p><p><strong>(iv)</strong> take these responses into account in considering whether reasonable adjustments can be made in order that the Employee can safely undertake and sustain work.</p><p><strong>(e)</strong> Report from Treating Medical Practitioner Where, after discussion with the Employee, the Employer continues to have a reasonable belief that the Employee is unfit to perform the duties, the Employer may request the Employee to obtain a report from the Employee&#39;s treating medical practitioner regarding the Employee&#39;s fitness for work. Where this occurs, the Employer will provide to the Employee, in</p><p>PART J – OCCUPATONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p>writing, the concerns and information that form the basis of the reasonable belief to assist the Employee&#39;s treating medical practitioner.</p><p><strong>(f)</strong> The Employee will:</p><p><strong>(i)</strong> advise the Employer of the Employee&#39;s treating medical practitioner;</p><p><strong>(ii)</strong> provide a copy of the report to the Employer; and</p><p><strong>(iii)</strong> meet with the Employer to discuss any report.</p><p><strong>82.3</strong> Report from IME If, on receipt of the report, and (where reasonably practicable) following discussion, the Employer continues to have a reasonable belief that the Employee is unfit for duty, or the Employee does not provide a report from the treating medical practitioner, the Employer may require the Employee to attend an independent medical practitioner (IME).</p><p><strong>(a)</strong> The Employer will:</p><p><strong>(i)</strong> pay for the cost and expenses of the appointment and report;</p><p><strong>(ii)</strong> provide a copy of the IME report to the Employee; and</p><p><strong>(iii)</strong> meet with the Employee to discuss any report.</p><p><strong>82.4</strong> Information to Employee before IME Before the Employee attends an IME under subclause 82.3 above, the Employee will be provided with a copy of:</p><p><strong>(a)</strong> the name of the proposed IME: and</p><p><strong>(b)</strong> any correspondence (including any supporting material) proposed to be sent to the IME.</p><p><strong>82.5</strong> Employee consultation and right to supplement information Before attending an IME, the Employee may:</p><p><strong>(a)</strong> supplement the material to be provided to the IME;</p><p><strong>(b)</strong> request to meet with the Employer to consult about the material the Employer proposes to provide the IME. The Employee&#39;s representative may attend the meeting.</p><p><strong>82.6</strong> Relationship to WIRC This subclause 82 does not apply to an injury that is the subject of an active WorkCover claim. Matters regarding an Employee&#39;s Fitness for Work regarding an injury that is the subject of a WorkCover claim shall be managed in accordance with the WIRC Act including the Employer&#39;s obligation to provide a safe work environment.</p><p><strong>82.7</strong> Safe Work Environment is paramount</p><p>PART J – OCCUPATONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p><strong>82.8</strong> Nothing in this clause 82 prevents an Employer from taking any reasonable step in the workplace to ensure a safe work environment.</p><p><strong>82.9</strong> Reasonable Adjustments</p><p><strong>(a)</strong> Where Employees have a disability (whether permanent or temporary) the Employer is required to make reasonable adjustments to enable the Employee to continue to perform their duties, subject to subclause 82.9(b) below.</p><p><strong>(b)</strong> An Employer is not required to make reasonable adjustments if the Employee could not or cannot adequately perform the genuine and reasonable requirements of the employment even after the adjustments are made.</p><p><strong>(c)</strong> Definitions</p><p><strong>(i)</strong> Disability has the same meaning as section 4 of the Equal Opportunity Act 2010 (Vic) (EO Act) and includes: <strong>(A)</strong> total or partial loss of a bodily function; or <strong>(B)</strong> presence in the body of organisms that may cause disease; <strong>(C)</strong> total or partial loss of a part of the body; or <strong>(D)</strong> malfunction of a part of the body including a mental or psychological disease or disorder or condition or disorder that results in a person learning more slowly than those without the condition or disorder.</p><p><strong>(ii)</strong> Reasonable adjustments has the same meaning as relevant facts and circumstances including: <strong>(A)</strong> the employee&#39;s circumstances, including the nature of the disability; <strong>(B)</strong> the nature of the Employee&#39;s role; <strong>(C)</strong> the nature of the adjustment required to accommodate the Employee&#39;s disability; <strong>(D)</strong> the financial circumstances of the Employer; <strong>(E)</strong> the size and nature of the workplace and the Employer&#39;s business; <strong>(F)</strong> the effect on the workplace and the Employer&#39;s business of making the adjustment including the financial impact, the number of persons who would benefit or be disadvantaged and the impact of efficiency and productivity;</p><p>PART J – OCCUPATONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p><strong>(G)</strong> the consequences for the Employer in making the adjustment, <strong>(H)</strong> the consequences for the Employee in not making the adjustment.</p><p>PART J – OCCUPATONAL HEALTH AND SAFETY AND RELATED MATTERS</p><p>Plain language terms: fit for duty, medical assessment.</p>',46)])])}const g=t(s,[["render",a]]);export{d as __pageData,g as default};
